// Append a required IP rule to storage account network ACLs
{
  "mode": "All",
  "displayName": "Append required IP rule to storage account network ACLs",
  "parameters": {
    "requiredIpRange": {
      "type": "String",
      "metadata": { "displayName": "Required allowed IP range" }
    }
  },
  "policyRule": {
    "if": {
      "field": "type",
      "equals": "Microsoft.Storage/storageAccounts"
    },
    "then": {
      "effect": "append",
      "details": [{
        "field": "Microsoft.Storage/storageAccounts/networkAcls.ipRules",
        "value": [{ "action": "Allow", "value": "[parameters('requiredIpRange')]" }]
      }]
    }
  }
}

// Append a default tag if absent (set a scalar property)
{
  "mode": "Indexed",
  "displayName": "Append environment tag if absent",
  "parameters": {
    "environment": {
      "type": "String",
      "metadata": { "displayName": "Environment value" }
    }
  },
  "policyRule": {
    "if": {
      "field": "tags['environment']",
      "exists": "false"
    },
    "then": {
      "effect": "append",
      "details": [{
        "field": "tags['environment']",
        "value": "[parameters('environment')]"
      }]
    }
  }
}

// Append required diagnostic category to storage account diagnostic settings
{
  "mode": "All",
  "displayName": "Append required diagnostic log category",
  "policyRule": {
    "if": {
      "field": "type",
      "equals": "microsoft.insights/diagnosticSettings"
    },
    "then": {
      "effect": "append",
      "details": [{
        "field": "microsoft.insights/diagnosticSettings/logs",
        "value": [{ "category": "StorageRead", "enabled": true }]
      }]
    }
  }
}

// Append for tag: adds only when absent, conflicts if wrong value exists
// Use this when you want the deployer's value preserved
{
  "policyRule": {
    "if": { "field": "tags['cost-center']", "exists": "false" },
    "then": {
      "effect": "append",
      "details": [{ "field": "tags['cost-center']", "value": "unassigned" }]
    }
  }
}

// Modify for tag: adds if absent OR replaces if wrong value
// Use this when you want the policy value to always win
{
  "policyRule": {
    "if": {
      "anyOf": [
        { "field": "tags['cost-center']", "exists": "false" },
        { "field": "tags['cost-center']", "notEquals": "correct-value" }
      ]
    },
    "then": {
      "effect": "modify",
      "details": {
        "roleDefinitionIds": ["/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"],
        "operations": [{ "operation": "addOrReplace", "field": "tags['cost-center']", "value": "correct-value" }]
      }
    }
  }
}

# append-ip-policy.tf

resource "azurerm_policy_definition" "append_corp_ip_rule" {
  name         = "append-corp-ip-rule"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Append corporate IP range to storage account network ACLs"
  management_group_id = var.corp_mg_id

  parameters = jsonencode({
    requiredIpRange = {
      type     = "String"
      metadata = { displayName = "Required IP Range" }
    }
  })

  policy_rule = jsonencode({
    if = {
      field  = "type"
      equals = "Microsoft.Storage/storageAccounts"
    }
    then = {
      effect = "append"
      details = [{
        field = "Microsoft.Storage/storageAccounts/networkAcls.ipRules"
        value = [{ action = "Allow", value = "[parameters('requiredIpRange')]" }]
      }]
    }
  })
}

resource "azurerm_management_group_policy_assignment" "append_corp_ip" {
  name                 = "append-corp-ip-rule"
  display_name         = "Append corporate IP range to storage network ACLs"
  policy_definition_id = azurerm_policy_definition.append_corp_ip_rule.id
  management_group_id  = var.corp_mg_id

  parameters = jsonencode({
    requiredIpRange = { value = "203.0.113.0/24" }
  })
  # Note: Append does NOT require a managed identity — no identity block needed
}

// Append multiple network ACL entries in one policy
{
  "mode": "All",
  "displayName": "Append corp network ACL rules to storage accounts",
  "policyRule": {
    "if": {
      "field": "type",
      "equals": "Microsoft.Storage/storageAccounts"
    },
    "then": {
      "effect": "append",
      "details": [
        {
          "field": "Microsoft.Storage/storageAccounts/networkAcls.ipRules",
          "value": [
            { "action": "Allow", "value": "203.0.113.0/24" },
            { "action": "Allow", "value": "198.51.100.0/24" }
          ]
        },
        {
          "field": "Microsoft.Storage/storageAccounts/networkAcls.virtualNetworkRules",
          "value": [
            { "id": "/subscriptions/11111111-1111-1111-1111-111111111111/resourceGroups/rg-platform/providers/Microsoft.Network/virtualNetworks/vnet-hub/subnets/snet-management", "action": "Allow" }
          ]
        }
      ]
    }
  }
}
